61	    applies: (customer) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
62	    percent: -LOYALTY_DISCOUNT_PERCENT,
63	  },
64	];
65	
66	const sumRulePercentages = <T>(rules: Rule<T>[], target: T, base: number): number =>
67	  rules.reduce(
68	    (sum, rule) => sum + (rule.applies(target) ? percentOf(base, rule.percent) : 0),
69	    0
70	  );
71	
72	const itemSurcharge = (item: any): number =>
73	  sumRulePercentages(ITEM_SURCHARGE_RULES, item, itemBasePremium(item));
74	
75	const calculateItemSurcharges = (items: any[]): number =>
76	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
77	
78	const calculatePolicyModifiers = (customer: any, policyBase: number): number =>
79	  sumRulePercentages(POLICY_MODIFIER_RULES, customer, policyBase);
80	
81	const quotePremium = (items: any[], customer: any): number => {
82	  const policyBase = calculateBasePremium(items);
83	  const itemSurcharges = calculateItemSurcharges(items);
84	  const policyModifiers = calculatePolicyModifiers(customer, policyBase);
85	  return Math.ceil(policyBase + policyModifiers + itemSurcharges + PROCESSING_FEE);
86	};
87	
88	export const runScenario = (scenario: any): unknown => {
89	  const items = scenario.steps[0].items;
90	  return { results: [{ premium: quotePremium(items, scenario.customer) }] };
91	};
